// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "forge-std/Test.sol";
import "./ExampleContract.sol";

contract ExampleContractTest is Test {
    ExampleContract example;

    function setUp() public {
        example = new ExampleContract();
    }

    function testDeposit() public {
        vm.deal(address(this), 1 ether);
        example.deposit{value: 1 ether}();
        assertEq(example.getBalance(address(this)), 1 ether);
    }

    function testWithdraw() public {
        vm.deal(address(this), 1 ether);
        example.deposit{value: 1 ether}();
        example.withdraw(1 ether);
        assertEq(example.getBalance(address(this)), 0);
    }

    function testReentrancyGuard() public {
        vm.deal(address(this), 1 ether);
        example.deposit{value: 1 ether}();

        // Attempt to reenter the withdraw function
        ReentrancyAttack attack = new ReentrancyAttack(address(example));
        vm.expectRevert(bytes("ReentrancyGuard: reentrant call"));
        attack.attack();
    }
}

contract ReentrancyAttack {
    ExampleContract example;

    constructor(address _example) {
        example = ExampleContract(_example);
    }

    receive() external payable {
        if (address(example).balance > 0) {
            example.withdraw(1 ether);
        }
    }

    function attack() external payable {
        example.deposit{value: 1 ether}();
        example.withdraw(1 ether);
    }
}
